// csvSyncBatchSize bounds each PUT /lists/{id}/contacts/batch call. The
// EmailOctopus docs recommend 100 subscribers per batch; any larger and
// the request body crosses the gateway's limit, any smaller and the
// per-batch overhead dominates wall-clock on large CSVs.
const csvSyncBatchSize = 100

// csvSyncDogfoodCap caps rows read when the dogfood matrix sets
// PRINTING_PRESS_DOGFOOD=1. The runner's 30s flat timeout would otherwise
// trip on real-world CSV sizes; happy-path needs to finish under that.
const csvSyncDogfoodCap = 5

// csvSyncBatchPause is the inter-batch sleep; pairs with the client's
// proactive rate limiter so back-to-back batches don't pile up against
// the EmailOctopus 10/sec ceiling.
const csvSyncBatchPause = 100 * time.Millisecond

// syncCSVReport is the per-run summary. Errors are listed inline so an
// agent driving this can resume after partial failure without re-reading
// stderr; rows_sent is what landed (after dogfood cap and per-batch
// failures), batches is the number of HTTP calls actually issued.
type syncCSVReport struct {
	RowsRead      int              `json:"rows_read"`
	RowsSent      int              `json:"rows_sent"`
	Batches       int              `json:"batches"`
	Errors        []syncCSVError   `json:"errors"`
	WouldSend     []map[string]any `json:"would_send,omitempty"`
	DryRun        bool             `json:"dry_run,omitempty"`
	DogfoodCapped bool             `json:"dogfood_capped,omitempty"`
	VerifySkipped bool             `json:"verify_skipped,omitempty"`
}

type syncCSVError struct {
	Batch int    `json:"batch"`
	Err   string `json:"err"`
}

// csvMapping resolves CSV columns to API payload fields. The mapping
// vocabulary is intentionally narrow (email, tag.*, field.*, status) so
// users can't accidentally route arbitrary data into unknown payload
// keys — every entry is validated at parse time.
type csvMapping struct {
	emailCol  string
	statusCol string
	fields    map[string]string // api field name -> csv column
	tags      map[string]string // tag label -> csv column (presence-as-bool)
}

func parseCSVMapping(specs []string) (*csvMapping, error) {
	m := &csvMapping{fields: map[string]string{}, tags: map[string]string{}}
	for _, raw := range specs {
		spec := strings.TrimSpace(raw)
		if spec == "" {
			continue
		}
		eq := strings.IndexByte(spec, '=')
		if eq < 1 || eq == len(spec)-1 {
			return nil, fmt.Errorf("invalid --map entry %q (expected key=column)", raw)
		}
		key := strings.TrimSpace(spec[:eq])
		col := strings.TrimSpace(spec[eq+1:])
		switch {
		case key == "email":
			m.emailCol = col
		case key == "status":
			m.statusCol = col
		case strings.HasPrefix(key, "field."):
			name := strings.TrimPrefix(key, "field.")
			if name == "" {
				return nil, fmt.Errorf("invalid --map entry %q (field name empty)", raw)
			}
			m.fields[name] = col
		case strings.HasPrefix(key, "tag."):
			name := strings.TrimPrefix(key, "tag.")
			if name == "" {
				return nil, fmt.Errorf("invalid --map entry %q (tag name empty)", raw)
			}
			m.tags[name] = col
		default:
			return nil, fmt.Errorf("unsupported --map key %q (use email, status, field.<name>, tag.<name>)", key)
		}
	}
	if m.emailCol == "" {
		return nil, fmt.Errorf("--map must include an email=<column> entry")
	}
	return m, nil
}

// buildSubscriber projects one CSV row into the EmailOctopus batch
// subscriber payload shape. Empty cells become zero-valued fields rather
// than null so the API doesn't reject the row with "expected string".
func buildSubscriber(row map[string]string, m *csvMapping) (map[string]any, bool) {
	email := strings.TrimSpace(row[m.emailCol])
	if email == "" {
		return nil, false
	}
	sub := map[string]any{"email_address": email}
	if m.statusCol != "" {
		if v := strings.TrimSpace(row[m.statusCol]); v != "" {
			sub["status"] = v
		}
	}
	if len(m.fields) > 0 {
		fields := map[string]any{}
		for apiName, col := range m.fields {
			if v, ok := row[col]; ok {
				fields[apiName] = v
			}
		}
		sub["fields"] = fields
	}
	if len(m.tags) > 0 {
		var tags []string
		for tag, col := range m.tags {
			if v := strings.TrimSpace(row[col]); v != "" && !strings.EqualFold(v, "false") && v != "0" {
				tags = append(tags, tag)
			}
		}
		if len(tags) > 0 {
			sub["tags"] = tags
		}
	}
	return sub, true
}

func newContactsSyncCSVCmd(flags *rootFlags) *cobra.Command {
	var listID string
	var mappings []string

	cmd := &cobra.Command{
		Use:   "sync-csv <csv_file>",
		Short: "Push contacts from a CSV into a list via the batch upsert endpoint",
		Example: `  # Sync a CSV with email + first-name field
  emailoctopus-pp-cli contacts sync-csv contacts.csv \
    --list c81c21ca-51cc-11f1-ad3e-ffeba75576ac \
    --map email=Email --map field.first_name=FirstName

  # Add a per-row tag based on a Plan column
  emailoctopus-pp-cli contacts sync-csv contacts.csv \
    --list c81c21ca-51cc-11f1-ad3e-ffeba75576ac \
    --map email=Email --map tag.pro=PlanIsPro

  # Preview the payload without sending
  emailoctopus-pp-cli contacts sync-csv contacts.csv \
    --list c81c21ca-51cc-11f1-ad3e-ffeba75576ac --map email=Email --dry-run`,
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) == 0 {
				return cmd.Help()
			}
			// Verify probes the command tree with positional-only args and no
			// flags. Short-circuit before the required-flag checks so the
			// mock-mode probe records a clean exit; real runs still enforce.
			if cliutil.IsVerifyEnv() {
				return printJSONFiltered(cmd.OutOrStdout(), syncCSVReport{VerifySkipped: true}, flags)
			}
			if listID == "" {
				return usageErr(fmt.Errorf("--list is required"))
			}
			if len(mappings) == 0 {
				return usageErr(fmt.Errorf("at least one --map entry is required (e.g. --map email=Email)"))
			}
			mapping, err := parseCSVMapping(mappings)
			if err != nil {
				return usageErr(err)
			}

			f, err := os.Open(args[0])
			if err != nil {
				return fmt.Errorf("opening CSV: %w", err)
			}
			defer f.Close()

			reader := csv.NewReader(f)
			reader.TrimLeadingSpace = true
			header, err := reader.Read()
			if err != nil {
				return fmt.Errorf("reading CSV header: %w", err)
			}
			colIdx := map[string]int{}
			for i, h := range header {
				colIdx[strings.TrimSpace(h)] = i
			}
			// Validate every referenced column actually appears in the header
			// up front so the user finds out about typos before the first PUT.
			for _, col := range mapping.allColumns() {
				if _, ok := colIdx[col]; !ok {
					return usageErr(fmt.Errorf("--map references unknown CSV column %q (header: %v)", col, header))
				}
			}

			dogfoodCap := cliutil.IsDogfoodEnv()
			var subscribers []map[string]any
			rowsRead := 0
			for {
				rec, rerr := reader.Read()
				if rerr == io.EOF {
					break
				}
				if rerr != nil {
					return fmt.Errorf("reading CSV row %d: %w", rowsRead+2, rerr)
				}
				row := map[string]string{}
				for col, i := range colIdx {
					if i < len(rec) {
						row[col] = rec[i]
					}
				}
				if sub, ok := buildSubscriber(row, mapping); ok {
					subscribers = append(subscribers, sub)
				}
				rowsRead++
				if dogfoodCap && rowsRead >= csvSyncDogfoodCap {
					break
				}
			}

			report := syncCSVReport{
				RowsRead:      rowsRead,
				DogfoodCapped: dogfoodCap,
			}

			if flags.dryRun || cliutil.IsVerifyEnv() {
				report.DryRun = flags.dryRun
				report.VerifySkipped = cliutil.IsVerifyEnv()
				report.WouldSend = subscribers
				return printJSONFiltered(cmd.OutOrStdout(), report, flags)
			}

			c, err := flags.newClient()
			if err != nil {
				return err
			}

			path := "/lists/" + listID + "/contacts/batch"
			for start := 0; start < len(subscribers); start += csvSyncBatchSize {
				end := start + csvSyncBatchSize
				if end > len(subscribers) {
					end = len(subscribers)
				}
				body := map[string]any{"subscribers": subscribers[start:end]}
				_, _, perr := c.Put(path, body)
				report.Batches++
				if perr != nil {
					report.Errors = append(report.Errors, syncCSVError{Batch: report.Batches, Err: perr.Error()})
					continue
				}
				report.RowsSent += end - start
				if end < len(subscribers) {
					time.Sleep(csvSyncBatchPause)
				}
			}
			return printJSONFiltered(cmd.OutOrStdout(), report, flags)
		},
	}

	cmd.Flags().StringVar(&listID, "list", "", "Target list id (required)")
	cmd.Flags().StringSliceVar(&mappings, "map", nil, "CSV-column mapping (e.g. email=Email, field.first_name=FirstName, tag.pro=PlanIsPro). Repeatable.")
	return cmd
}

// allColumns returns every CSV column name referenced by the mapping so
// the row reader can validate them against the header before starting.
func (m *csvMapping) allColumns() []string {
	seen := map[string]struct{}{}
	add := func(c string) {
		if c == "" {
			return
		}
		seen[c] = struct{}{}
	}
	add(m.emailCol)
	add(m.statusCol)
	for _, c := range m.fields {
		add(c)
	}
	for _, c := range m.tags {
		add(c)
	}
	out := make([]string, 0, len(seen))
	for c := range seen {
		out = append(out, c)
	}
	return out
}
